pub enum HarnessResult {
  RejectedPrecondition,
  FailedPostcondition(TestCaseError),
  Passed,
}

/** Contract-based test harness for the initialize entry point
  */
pub fn testInitializeCB() -> HarnessResult
{
  // [InvokeEntryPoint]: Invoke the entry point
  crate::tcp_tct_initialize();

  // [RetrieveOutState]: retrieve values of the output ports via get operations and GUMBO declared local state variable
  let currentFanState = get_currentFanState();
  let currentSetPoint = get_currentSetPoint();
  let fanError = get_fanError();
  let latestTemp = get_latestTemp();
  let api_fanCmd = get_fanCmd();

  // [CheckPost]: invoke the oracle function
  if !GUMBOX::initialize_IEP_Post (currentFanState, currentSetPoint, fanError, latestTemp, api_fanCmd) {
    return HarnessResult::FailedPostcondition(
      TestCaseError::Fail("Postcondition failed: incorrect output behavior".into())
    );
  }

  return HarnessResult::Passed
}

#[macro_export]
macro_rules!
testInitializeCB_macro {
  (
    $test_name: ident,
    config: $config:expr
  ) => {
    proptest!{
      #![proptest_config($config)]
      #[test]
      #[serial]
      fn $test_name(empty in ::proptest::strategy::Just(())) {
        match $crate::test::util::cb_apis::testInitializeCB() {
          $crate::test::util::cb_apis::HarnessResult::RejectedPrecondition => {
            unreachable!("This branch is infeasible")
          }
          $crate::test::util::cb_apis::HarnessResult::FailedPostcondition(e) => {
            return Err(e)
          }
          $crate::test::util::cb_apis::HarnessResult::Passed => { }
        }
      }
    }
  };
}

/** Contract-based test harness for the compute entry point
  *
  * @param api_currentTemp incoming event data port
  * @param api_fanAck incoming event data port
  * @param api_setPoint incoming event data port
  */
pub fn testComputeCB(
  api_currentTemp: Option<TempControl_SysVerif::Temperature>,
  api_fanAck: Option<TempControl_SysVerif::FanAck>,
  api_setPoint: Option<TempControl_SysVerif::SetPoint>) -> HarnessResult
{
  // Initialize the app
  crate::tcp_tct_initialize();

  // [SaveInLocal]: retrieve and save the current (input) values of GUMBO-declared local state variables as retrieved
  //                from the component state
  let In_currentFanState: TempControl_SysVerif::FanCmd = get_currentFanState();
  let In_currentSetPoint: TempControl_SysVerif::SetPoint = get_currentSetPoint();
  let In_fanError: bool = get_fanError();
  let In_latestTemp: TempControl_SysVerif::Temperature = get_latestTemp();

  // [CheckPre]: check/filter based on pre-condition.
  if !GUMBOX::compute_CEP_Pre (In_currentFanState, In_currentSetPoint, In_fanError, In_latestTemp, api_currentTemp, api_fanAck, api_setPoint) {
    return HarnessResult::RejectedPrecondition;
  }

  // [PutInPorts]: Set values on the input ports
  put_currentTemp(api_currentTemp);
  put_fanAck(api_fanAck);
  put_setPoint(api_setPoint);

  // [InvokeEntryPoint]: Invoke the entry point
  crate::tcp_tct_timeTriggered();

  // [RetrieveOutState]: retrieve values of the output ports via get operations and GUMBO declared local state variable
  let currentFanState = get_currentFanState();
  let currentSetPoint = get_currentSetPoint();
  let fanError = get_fanError();
  let latestTemp = get_latestTemp();
  let api_fanCmd = get_fanCmd();

  // [CheckPost]: invoke the oracle function
  if !GUMBOX::compute_CEP_Post(In_currentFanState, In_currentSetPoint, In_fanError, In_latestTemp, currentFanState, currentSetPoint, fanError, latestTemp, api_currentTemp, api_fanAck, api_setPoint, api_fanCmd) {
    return HarnessResult::FailedPostcondition(TestCaseError::Fail("Postcondition failed: incorrect output behavior".into()));
  }

  return HarnessResult::Passed
}

/** Contract-based test harness for the compute entry point
  */
pub fn testComputeCB_container(container: PreStateContainer) -> HarnessResult
{
  return testComputeCB(container.api_currentTemp, container.api_fanAck, container.api_setPoint)
}

